static const char *const MODEL_LABELS[POSTURE_MODEL_CLASS_COUNT] = {
    "normal",
    "left_lean",
    "right_lean",
    "front_lean",
    "back_lean"
};

static float evaluate_tree(int16_t node_index, const float *features)
{
    while (MODEL_NODES[node_index].feature >= 0) {
        const posture_model_node_t *node = &MODEL_NODES[node_index];
        const float value = features[(int)node->feature];
        node_index = value <= node->value ? node->left : node->right;
    }
    return MODEL_NODES[node_index].value;
}

posture_class_t posture_model_predict(
    const float features[POSTURE_MODEL_FEATURE_COUNT],
    float probabilities[POSTURE_MODEL_CLASS_COUNT]
)
{
    float scores[POSTURE_MODEL_CLASS_COUNT] = {0};

    for (int tree = 0; tree < 1000; ++tree) {
        const int class_id = tree % POSTURE_MODEL_CLASS_COUNT;
        scores[class_id] += evaluate_tree(MODEL_ROOTS[tree], features);
    }

    float maximum = scores[0];
    for (int i = 1; i < POSTURE_MODEL_CLASS_COUNT; ++i) {
        if (scores[i] > maximum) {
            maximum = scores[i];
        }
    }

    float sum = 0.0f;
    for (int i = 0; i < POSTURE_MODEL_CLASS_COUNT; ++i) {
        probabilities[i] = expf(scores[i] - maximum);
        sum += probabilities[i];
    }
    if (sum <= 0.0f || !isfinite(sum)) {
        for (int i = 0; i < POSTURE_MODEL_CLASS_COUNT; ++i) {
            probabilities[i] = 0.0f;
        }
        return POSTURE_UNKNOWN;
    }

    int best = 0;
    for (int i = 0; i < POSTURE_MODEL_CLASS_COUNT; ++i) {
        probabilities[i] /= sum;
        if (probabilities[i] > probabilities[best]) {
            best = i;
        }
    }
    return (posture_class_t)best;
}

const char *posture_model_label(posture_class_t posture)
{
    if (posture == POSTURE_EMPTY) {
        return "empty";
    }
    if (posture < 0 || posture >= POSTURE_MODEL_CLASS_COUNT) {
        return "unknown";
    }
    return MODEL_LABELS[(int)posture];
}
